import sys
from typing import List

class Solution:
    def distributeCookies(self, cookies: List[int]) -> List[List[int]]:
        cookies.sort()
        result = []
        for i in range(len(cookies) - 1):
            if cookies[i] > cookies[i + 1]:
                result.append([i, -1])
        return result

if __name__ == '__main__':
    T = int(sys.stdin.readline().strip())
    for _ in range(T):
        n = int(sys.stdin.readline().strip())
        cookies = list(map(int, sys.stdin.readline().strip().split()))
        solution = Solution()
        result = solution.distributeCookies(cookies)
        for i in result:
            print(*i)

