#include <iostream>
using namespace std;

class Solution {
public:
vector<pair<int,int>> distributeCookies(vector<int>& cookies) {
    sort(cookies.begin(), cookies.end());
    vector<pair<int,int>> result;
    for(int i = 0; i < cookies.size(); i++)
    {
        if(i == cookies.size() - 1 || cookies[i] > cookies[i+1])
            result.push_back({i, -1});
    }
    return result;
}
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    int T = 1;
    while(T--)
    {
        int n; cin >> n;
        vector<int> cookies(n);
        for(int i = 0; i < n; i++)
            cin >> cookies[i];
        Solution solution;
        auto result = solution.distributeCookies(cookies);
        for(auto &i : result)
            cout << i.first << ' ' << i.second << endl;
    }
    return 0;
}
